import{VectorField}from"/applets/vector-fields/scripts/class.min.js";import{createEphemeralApplet,hsvToHex}from"/scripts/applets/applet.min.js";import{createDesmosGraphs,desmosBlack,desmosBlue,desmosGraphs,desmosGraphsLoaded,desmosPurple,desmosRed,getColoredParametricCurve,getDesmosBounds,getDesmosSlider,getDesmosVector}from"/scripts/src/desmos.min.js";import{$,raw}from"/scripts/src/main.min.js";export default function(){function e(c){return hsvToHex((270+-75*(Math.sign(c)+1)+180)/360,1,.4*Math.abs(c))}createDesmosGraphs({slicingAndBoundaries:{bounds:{xmin:-.25,xmax:1.25,ymin:-.25,ymax:1.25,zmin:-3,zmax:3},expressions:[{latex:raw`y = \sqrt{x}\{ 0 \leq x \leq 1 \}`,color:desmosBlack},{latex:raw`y = 0\{ 0 \leq x \leq 1 \}`,color:desmosBlack},{latex:raw`x = 1\{ 0 \leq y \leq 1 \}`,color:desmosBlack},...getDesmosSlider({expression:raw`x_0 = 0.75`,min:0,max:1,secret:!1}),{latex:raw`x = x_0\{ 0 \leq y \leq \sqrt{x_0} \}`,color:desmosPurple}]},negativeBoundaryCurve:{bounds:{xmin:-.25,xmax:1.25,ymin:-.25,ymax:1.25,zmin:-3,zmax:3},expressions:[{latex:raw`f(x) = \sqrt{x}`,hidden:!0,secret:!0},{latex:raw`y = \sqrt{x}\{ 0 \leq x \leq 1 \}`,color:desmosPurple},{latex:raw`y = 0\{ 0 \leq x \leq 1 \}`,color:desmosBlue},{latex:raw`x = 1\{ 0 \leq y \leq 1 \}`,color:desmosRed},...getDesmosVector({from:["0.4","f(0.4)"],to:["0.4 + 0.001","f(0.4) + 0.001f'(0.4)"],color:desmosPurple,arrowSize:"0.05"}),...getDesmosVector({from:["0.5","0"],to:["0.5 - 0.001","0"],color:desmosBlue,arrowSize:"0.05"}),...getDesmosVector({from:["1","0.5"],to:["1","0.5 - 0.001"],color:desmosRed,arrowSize:"0.05"})]},positiveBoundaryCurve:{bounds:{xmin:-.25,xmax:1.25,ymin:-.25,ymax:1.25,zmin:-3,zmax:3},expressions:[{latex:raw`f(x) = \sqrt{x}`,hidden:!0,secret:!0},{latex:raw`y = \sqrt{x}\{ 0 \leq x \leq 1 \}`,color:desmosPurple},{latex:raw`y = 0\{ 0 \leq x \leq 1 \}`,color:desmosBlue},{latex:raw`x = 1\{ 0 \leq y \leq 1 \}`,color:desmosRed},...getDesmosVector({from:["0.4","f(0.4)"],to:["0.4 - 0.001","f(0.4) - 0.001f'(0.4)"],color:desmosPurple,arrowSize:"0.05"}),...getDesmosVector({from:["0.5","0"],to:["0.5 + 0.001","0"],color:desmosBlue,arrowSize:"0.05"}),...getDesmosVector({from:["1","0.5"],to:["1","0.5 + 0.001"],color:desmosRed,arrowSize:"0.05"})]},cycloid:{bounds:{xmin:-1,xmax:2,ymin:-.5,ymax:2.5},expressions:[{latex:raw`(t - \sin(2\pi t), 1 - \cos(2\pi t))`,color:desmosPurple}]},flux:{alwaysDark:!0,highContrast:!0,bounds:{xmin:-3,xmax:3,ymin:-3,ymax:3},options:{expressions:!1},expressions:[{latex:raw`l_1(t) = (2\cos(t), 2\sin(t))`},{latex:raw`l_2(t) = (-\sqrt{3}, -1) + t(2\sqrt{3}, 0)`},...getColoredParametricCurve({fieldFunction:(x,y)=>[-y,-x+y],pathFunction:t=>[2*Math.cos(t),2*Math.sin(t)],pathFunctionDesmos:raw`l_1(t)`,useUnitNormal:!0,minT:-Math.PI/6,maxT:7*Math.PI/6,numSlices:100,colorFunction:e}),...getColoredParametricCurve({fieldFunction:(x,y)=>[-y,-x+y],pathFunction:t=>[-Math.sqrt(3)+2*Math.sqrt(3)*t,-1],pathFunctionDesmos:raw`l_2(t)`,useUnitNormal:!0,minT:0,maxT:1,numSlices:100,colorFunction:e})]}}),desmosGraphsLoaded.flux.then(()=>{createEphemeralApplet($("#flux-canvas"),canvas=>{const s=new VectorField({canvas:canvas,useFullscreenButton:!1,useResetButton:!1,transparency:!0,onDrawFrame:function(){var e=getDesmosBounds(desmosGraphs.flux);s.wilson.resizeWorld({width:e.xmax-e.xmin,height:e.ymax-e.ymin,centerX:(e.xmin+e.xmax)/2,centerY:(e.ymin+e.ymax)/2})},minWorldWidth:.01,maxWorldWidth:100,minWorldHeight:.01,maxWorldHeight:100});return s.allowFullscreenWithKeyboard=!1,s.allowResetWithKeyboard=!1,s.loadPromise.then(()=>{s.run({resolution:500,maxParticles:5e3,generatingCode:"(-y * 0.5, (-x + y) * 0.5)",dt:.002,worldWidth:5,hue:.6,saturation:.85,brightness:.85,darkenWhenSlow:!0})}),s})})}